var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐야, 저게……?","JPN":"なんだ、あれ……？","ENG":"Huh? What's...?","TWN":"什麼，這是……？"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"잘 잤냐, 허접?","JPN":"おはよう、ヘタクソ。","ENG":"Sleep well, scurvy dog?","TWN":"早安，嘍囉？"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"저기 바쁘게 뛰어다니는 녀석들은 다들 잘 잔 모양인데.","JPN":"あっちで忙しく走り回ってる奴らはよく眠れたようだな。","ENG":"Looks like all the ones running around over there slept well.","TWN":"那邊忙進忙出的傢伙似乎睡得不錯。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"흐음- 언뜻 보기에도 출항을 준비하는 배가 열 척은 넘어 보이는데?","JPN":"ふーん、パッと見て、出航する準備をしてる船が10隻は超えそうだな。","ENG":"Hmm... There seems to be over ten ships ready for departure.","TWN":"嗯嗯，看起來好像有十幾艘船準備出海？"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저기 어선도 있어요. 내항에 남아 있던 배들을 있는 대로 긁어온 모양이네요.","JPN":"あそこに漁船もありますわ。内港に残っていた船をかき集めてきたようですね。","ENG":"There are also fishing ships over there. It looks as if they gathered all the ships in port.","TWN":"那邊還有一艘漁船，他們一定是把內港所有的船隻都搜刮來了。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"말도 안 돼. 분명 어제까지만 해도 다들 바다라면 질색했으면서…….","JPN":"あり得ない。昨日まではみんな海はうんざりだって言ってたくせに……","ENG":"No way. They all said they wouldn't go out to sea yesterday...","TWN":"怎麼可能，這些人明明昨天還不願意出海……"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"누구 말마따나, 다들 돈에 눈이 멀었나 보지.","JPN":"誰かの言うとおり、みんな金に目がくらんでるみたいだな。","ENG":"Just like someone said, they're all in it for the money.","TWN":"應該就是像某人說的見錢眼開吧。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"어이, 해적 놈들. 짐 싣는데 걸리적거리니까. 비켜!","JPN":"おい、海賊ども。積み込みの邪魔だ。どけ！","ENG":"Hey, pirate trash! Move! We're loading the ship. You're getting in our way!","TWN":"喂，海盜，別擋路，我們在搬運行李，閃開！"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"우린 보물이 가라앉기 전에 빨리 건져내러 가야 한다고.","JPN":"俺たちは宝が沈む前に早く引き揚げにいかなきゃなんねえんだよ。","ENG":"We need to get there fast before all the treasure sinks to the bottom.","TWN":"我們得趕在寶藏沉入海底之前，把它們打撈上來。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"부두가 네놈들 거냐? 줄이나 똑바로 서.","JPN":"波止場がてめえらだけのもんだと思ってんのか？　ちゃんと並べ。","ENG":"You think this port's yours, huh? Get in line.","TWN":"碼頭是你家嗎？快排好隊。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"우릴 쫓아올 셈이라면 발목 잡지나 말라고.","JPN":"俺らを追ってくるつもりなら、足手まといになるなよ。","ENG":"All you're doing is trailing us, so don't get in our way, got that?","TWN":"想要跟著我們，就不要扯後腿。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"흥, 그건 우리가 할 소리다. 이번엔 뒤통수 치지 마.","JPN":"ふん、それはこっちのセリフだ。今度は裏切るな。","ENG":"Hmph. That goes for you too. Don't double-cross us again this time.","TWN":"哼，這句話該我們說。這次休想暗算我們。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"케케케, 뒤통수 맞는 게 무서우면 그냥 여기서 포기하고 내빼시던지.","JPN":"ケケケ、裏切られんのが怖けりゃここで諦めて逃げろよ。","ENG":"Kekeke, maybe you should give up now if you're so scared of getting backstabbed.","TWN":"嘿嘿嘿，如果害怕被人暗算，那就趁早放棄，趕快離開這裡吧。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"나중에 귀찮을 일 없게 여기서 끝장을 볼까?!","JPN":"後で面倒くさくならねえように、ここで決着をつけるか！？","ENG":"How about we settle things right now, huh?!","TWN":"不如就在這裡解決他們，免得以後麻煩？"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"다들 준비는 잘 되어가고 있나?","JPN":"みんな、ちゃんと準備できてるか？","ENG":"How's the preparation going?","TWN":"大家都準備好了嗎？"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"생각한 것보다 미끼가 많이 모인 것 같아 다행이군.","JPN":"思ったよりオトリがたくさん集まったようで良かったな。","ENG":"Glad to see we've got plenty of bait.","TWN":"很好，看來誘餌比想像的要多呢。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"늦잖아, 보물사냥꾼. 벌써 해가 중천이라고.","JPN":"遅いだろ、トレジャーハンター。もう真っ昼間だぜ。","ENG":"You're late, treasure hunter. It's midday already.","TWN":"寶藏獵人，你怎麼這麼晚來，太陽都曬屁股咧？"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"당신,\xA0심해역에서 살아 돌아왔을 정도면 안전한 항로는 꿰고 있는 거겠지?","JPN":"あんた、深海域から生きて戻れたんなら、安全な航路を知ってるんだろ？","ENG":"Hey, you've returned from the deep sea area, so you know the safest route, right?","TWN":"你既然能從深海域活著回來，那你應該知道安全航線吧？"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"범람한 바다에선 비교적 안전한 편이지.","JPN":"氾濫した海では比較的安全だ。","ENG":"More or less safe across the flooded ocean, sure.","TWN":"自然會比在翻騰的海洋裡安全些。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}}]`);export{e as default};